mapper.update:
UPDATE reply
SET reply_step = reply_step + 1
WHERE reply_ref = #{reply_ref}
  AND reply_step > #{reply_step}

mapper.select:
SELECT * FROM ( SELECT , ROW_NUMBER() OVER (ORDER BY r.reply_ref ASC, r.reply_step ASC) AS rn FROM reply r JOIN member m ON r.mem_idx = m.mem_idx WHERE r.board_idx = #{board_idx}
AND r.reply_is_deleted = 'N'
) WHERE rn BETWEEN #{start} AND #{end}
